phase1.code:
using UnityEngine;

// Class definition — a blueprint for creating objects
public class Player
{
    // Fields (data)
    public string name;
    public int health;
    public int attackPower;
    public int defense;

    // Constructor — called when a Player object is created
    public Player(string playerName, int startingHealth)
    {
        name = playerName;
        health = startingHealth;
        attackPower = 10;
        defense = 5;
        Debug.Log("Player " + name + " created!");
    }

    // Method (behavior)
    public void TakeDamage(int damage)
    {
        int actualDamage = Mathf.Max(damage - defense, 1);
        health -= actualDamage;
        Debug.Log(name + " took " + actualDamage + " damage! Health: " + health);
    }

    public void DisplayStats()
    {
        Debug.Log("=== " + name + " ===");
        Debug.Log("Health: " + health);
        Debug.Log("Attack: " + attackPower);
        Debug.Log("Defense: " + defense);
    }
}

// MonoBehaviour class to test the Player class
public class ClassesAndObjects : MonoBehaviour
{
    void Start()
    {
        // Creating objects (instances) from the Player class
        Player hero = new Player("Hero", 100);
        Player enemy = new Player("Goblin", 30);

        hero.DisplayStats();
        enemy.DisplayStats();

        // Using methods
        hero.TakeDamage(25);
        enemy.TakeDamage(15);

        // Accessing fields directly (public)
        Debug.Log("Hero's attack: " + hero.attackPower);
    }
}

